// DeepCopyObject implements runtime.Object for Widget.
func (w *Widget) DeepCopyObject() runtime.Object {
	if w == nil {
		return nil
	}
	return &Widget{
		TypeMeta:   w.TypeMeta,
		ObjectMeta: *w.ObjectMeta.DeepCopy(),
		Spec:       w.Spec,
	}
}

// DeepCopyObject implements runtime.Object for WidgetList.
func (wl *WidgetList) DeepCopyObject() runtime.Object {
	if wl == nil {
		return nil
	}
	items := make([]Widget, len(wl.Items))
	for i, item := range wl.Items {
		items[i] = *item.DeepCopyObject().(*Widget)
	}
	return &WidgetList{
		TypeMeta: wl.TypeMeta,
		ListMeta: *wl.ListMeta.DeepCopy(),
